// Returns pointer to the icon bitmap for a given ICON_xxx constant.
static const uint16_t* weatherIconData(int iconType) {
  switch (iconType) {
    case ICON_SUNNY         : return ICON_DATA_SUNNY;
    case ICON_PARTLY_CLOUDY : return ICON_DATA_PARTLY_CLOUDY;
    case ICON_CLOUDY        : return ICON_DATA_CLOUDY;
    case ICON_RAIN          : return ICON_DATA_RAIN;
    case ICON_SNOW          : return ICON_DATA_SNOW;
    case ICON_STORM         : return ICON_DATA_STORM;
    case ICON_THUNDERSTORM  : return ICON_DATA_THUNDERSTORM;
    case ICON_WINDY         : return ICON_DATA_WINDY;
    case ICON_MOON          : return ICON_DATA_MOON;
    case ICON_RAINBOW       : return ICON_DATA_RAINBOW;
    default:                 return ICON_DATA_SUNNY;
  }
}

